mapper.select:
select DISTINCT fu.email as email , aarh.date as date ,CONVERT(varchar(10), aarh.date,120 ) as date_str from fnd_user fu join pm_employee_job pej on fu.employee_id = pej.employee_id and fu.enabled_flag =1 and pej.enabled_flag = 1 and pej.job_main_flag = 1 join fnd_dept fd on fd.id = pej.dept_id and fd.enabled_flag =1 and fd.deleted_flag = 0 join ac_attendance_record_history aarh on pej.employee_id = aarh.employee_id
and aarh.id in (
#{item}
)

select distinct pe.name as to_name, fu.email as email, aarh.date as date, pet.name as from_name, CONVERT(varchar(10), aarh.date,120 ) as date_str from pm_employee pe join ac_emp_depts aed on pe.id = aed.employee_id and aed.enabled_flag =1 and aed.data_type = 'documenter' and pe.enabled_flag =1 and pe.leave_flag = 0
join fnd_user fu on aed.employee_id = fu.employee_id and fu.enabled_flag = 1 join pm_employee_job pej on pej.dept_id = aed.dept_id and pej.enabled_flag = 1 and pej.job_main_flag = 1 join ac_attendance_record_history aarh on pej.employee_id = aarh.employee_id
and aarh.id in (
#{item}
)
and CHARINDEX('sunten',fu.email) <> 0 join pm_employee pet on pet.enabled_flag =1 and pet.id = pej.employee_id

mapper.sql:
select CASE WHEN EXISTS ( SELECT 1 FROM pm_employee_job pej JOIN fnd_dept fd ON pej.job_id = fd.admin_job_id AND pej.enabled_flag = 1 AND fd.enabled_flag = 1 AND fd.deleted_flag = 0 AND pej.employee_id = aarh.employee_id ) or EXISTS(select 1 from fnd_authorization fa join pm_employee_job pej on pej.employee_id = fa.authorization_to where pej.enabled_flag = 1 and fa.enable_flag = 1 and getdate() between fa.begin_date and fa.end_date and fa.authorization_type = 'ac'
and pej.employee_id = #{criteria.baseQueryEmpId, jdbcType = BIGINT}
) THEN 1 ELSE 0 END AS aacr_record_is_charge_flag,
CASE WHEN EXISTS ( SELECT 1 FROM pm_employee_job pej JOIN fnd_dept fd ON pej.job_id = fd.admin_job_id AND pej.enabled_flag = 1 AND fd.enabled_flag = 1 AND fd.deleted_flag = 0 AND pej.employee_id = aarh.employee_id ) then 1 else 0 end as aacr_record_plus_charge_flag,
(select dept_name from fnd_dept fdt where fds.ext_dept_id = fdt.id) AS pe_dept_name, (select dept_name from fnd_dept fdt where fds.ext_department_id = fdt.id) AS pe_department, (select dept_name from fnd_dept fdt where fds.ext_team_id = fdt.id) AS pe_team, aarh.abnromal_attendance_record_id, aarh.employee_id,aarh.date,aarh.last_paragraph_end_time,aarh.next_period_start_time,aarh.rest_flag,aarh.no_scheduling, aarh.rest_day_clock,aarh.all_day_no_clock,aarh.office_time_clock,aarh.no_clock_in,aarh.abnormal_clock_in_time, aarh.no_clock_after_work,aarh.alt_first_time_from,aarh.alt_first_time_to,aarh.alt_extend1_time_flag,aarh.alt_second_time_from, aarh.alt_second_time_to,aarh.alt_extend2_time_flag,aarh.alt_third_time_from,aarh.alt_third_time_to,aarh.alt_extend3_time_flag, aarh.alt_rest_day_flag,aarh.attribute1,aarh.attribute2,aarh.attribute3,aarh.attribute4,aarh.attribute5,aarh.id, aarh.dispose_flag,aarh.result,aacr.date AS aacr_date,aacr.ac_attendance_record_history_id AS aacr_ac_attendance_record_history_id, aacr.clock_time AS aacr_clock_time,aacr.id AS aacr_id,aacr.dispose_by AS aacr_dispose_by,aacr.dispose_time AS aacr_dispose_time, case when isnull(aacr.check_result, '') = '' then aacr.dispose_result else aacr.check_result end as aacr_target_result, case when isnull(aacr.check_describes, '') = '' then aacr.dispose_describes else aacr.check_describes end as aacr_target_describes, aacr.dispose_result as aacr_dispose_result, aacr.dispose_describes as aacr_dispose_describes, aacr.check_result as aacr_check_result, aacr.check_describes as aacr_check_describes, aacr.req_code AS aacr_req_code, aacr.state AS aacr_state, aacr.admin_result AS aacr_admin_result, aacr.oa_remark AS aacr_oa_remark, aacr.code_status as aacr_code_status, aacr.leader_result as aacr_leader_result, aacr.commit_flag as aacr_commit_flag, pe.work_card AS pe_work_card, pe.NAME AS pe_name,pe.id AS pe_id, fds.id as dept_id, pejs.job_id as job_id, pejs.id as pej_id FROM ac_attendance_record_history aarh JOIN ac_abnormal_clock_record aacr ON aacr.ac_attendance_record_history_id = aarh.id JOIN pm_employee_job pejs ON aarh.employee_id = pejs.employee_id and pejs.enabled_flag = 1 and pejs.job_main_flag = 1 JOIN pm_employee pe ON pejs.employee_id = pe.id JOIN fnd_dept fds ON fds.id = pejs.dept_id and fds.enabled_flag = 1 and fds.deleted_flag = 0

union
where (1 = 1
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 and pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND EXISTS ( SELECT 1 FROM pm_employee_job pejst WHERE pejst.id = pejs.id AND pejst.job_id != isnull(( SELECT fdst.admin_job_id FROM fnd_dept fdst WHERE fdst.id = fds.id ), -1 ))
and aarh.employee_id != #{criteria.teamRemoveSelfId, jdbcType = BIGINT}
AND aacr.code_status = #{criteria.teamCodeStatus, jdbcType = VARCHAR}
AND ( (isnull(aacr.commit_flag, 0) = 0 and (aacr.code_status = 'documentor' or aacr.code_status = 'leader' or aacr.code_status = 'person')) or (isnull(aacr.commit_flag, 0) = 0 and (aacr.code_status = 'leaderRepulse' or aacr.code_status = 'acAdminRepulse' or aacr.code_status = 'leaderRepulseToPerson')))
AND isnull(aacr.commit_flag,0) = #{criteria.teamCommitFlag, jdbcType = BIT}
and 1 = 0
)
or (exists( select 1 from fnd_dept fdx join pm_employee_job pejx on pejx.employee_id = #{criteria.higherLevelEmployeeId, jdbcType = BIGINT} and pejx.enabled_flag = 1 and fdx.admin_job_id = pejx.job_id join fnd_dept fdtx on fdtx.parent_id = fdx.id and fdtx.enabled_flag = 1 join pm_employee_job pejtx on pejtx.job_id = fdtx.admin_job_id and pejtx.enabled_flag = 1 where pejtx.employee_id = aarh.employee_id) and aacr.code_status = 'leader' and aacr.commit_flag = 1 )
-- 授权专用
or (exists( select 1 from fnd_dept fdx join pm_employee_job pejx on pejx.enabled_flag = 1 and fdx.admin_job_id = pejx.job_id join fnd_dept fdtx on fdtx.parent_id = fdx.id and fdtx.enabled_flag = 1
and fdtx.id in
#{item, jdbcType=BIGINT}
join pm_employee_job pejtx on pejtx.job_id = fdtx.admin_job_id and pejtx.enabled_flag = 1 where pejtx.employee_id = aarh.employee_id) and aacr.code_status = 'leader' and aacr.commit_flag = 1 )

union
where 1 = 1
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 and pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND EXISTS ( SELECT 1 FROM pm_employee_job pejst WHERE pejst.id = pejs.id AND pejst.job_id != isnull(( SELECT fdst.admin_job_id FROM fnd_dept fdst WHERE fdst.id = fds.id ), -1 ))
AND aacr.code_status = #{criteria.docCodeStatus, jdbcType = VARCHAR}
AND (aacr.code_status = 'leader' or aacr.code_status = 'documentor')
AND ( (isnull(aacr.commit_flag, 0) = 0 and (aacr.code_status = 'documentor' or aacr.code_status = 'leader' or aacr.code_status = 'person')) or (isnull(aacr.commit_flag, 0) = 0 and (aacr.code_status = 'leaderRepulse' or aacr.code_status = 'acAdminRepulse' or aacr.code_status = 'leaderRepulseToPerson')))
AND isnull(aacr.commit_flag, 0) = #{criteria.docCommitFlag, jdbcType = BIT}
AND (aacr.code_status = 'documentor' or aacr.code_status = 'leaderRepulse' or aacr.code_status = 'acAdminRepulse' or aacr.code_status = 'leaderRepulseToPerson' )

union
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 and pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND EXISTS ( SELECT 1 FROM pm_employee_job pejst WHERE pejst.id = pejs.id AND pejst.job_id != isnull(( SELECT fdst.admin_job_id FROM fnd_dept fdst WHERE fdst.id = fds.id ), -1 ))

union
where (1 = 1
and pejs.dept_id IN
#{item, jdbcType=BIGINT}
AND pejs.job_id != isnull(fds.admin_job_id,-1)
and aarh.employee_id != #{criteria.teamRemoveSelfId, jdbcType = BIGINT}
AND aarh.code_status = #{criteria.teamCodeStatus, jdbcType = VARCHAR}
AND ( (isnull(aarh.commit_flag, 0) = 0 and (aarh.code_status = 'documentor' or aarh.code_status = 'leader' or aarh.code_status = 'person')) or (isnull(aarh.commit_flag, 0) = 0 and (aarh.code_status = 'leaderRepulse' or aarh.code_status = 'acAdminRepulse' or aarh.code_status = 'leaderRepulseToPerson')) )
AND isnull(aarh.commit_flag,0) = #{criteria.teamCommitFlag, jdbcType = BIT}
and 1 = 0
)
or ( 1 = 1
-- 查下级的管理人员
and pejs.dept_id IN
#{item, jdbcType=BIGINT}
and exists( select 1 from fnd_dept fdx join pm_employee_job pejx on pejx.employee_id = #{criteria.higherLevelEmployeeId, jdbcType = BIGINT} and pejx.enabled_flag = 1 and fdx.admin_job_id = pejx.job_id join fnd_dept fdtx on fdtx.parent_id = fdx.id and fdtx.enabled_flag = 1 join pm_employee_job pejtx on pejtx.job_id = fdtx.admin_job_id and pejtx.enabled_flag = 1 where pejtx.employee_id = aarh.employee_id) and aarh.code_status = 'leader' and aarh.commit_flag = 1 )
-- 授权专用， 查授权部门下的所有人员
or (
pejs.dept_id IN
#{item, jdbcType=BIGINT}
and exists( select 1 from fnd_dept fdtx join pm_employee_job pejtx on pejtx.job_id = fdtx.admin_job_id and pejtx.enabled_flag = 1 where pejtx.employee_id = aarh.employee_id and fdtx.enabled_flag = 1
and fdtx.id in
#{item, jdbcType=BIGINT}
) and aarh.code_status = 'leader' and aarh.commit_flag = 1 )

union
where 1 = 1
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 and pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND EXISTS ( SELECT 1 FROM pm_employee_job pejst WHERE pejst.id = pejs.id AND pejst.job_id != isnull((SELECT fdst.admin_job_id FROM fnd_dept fdst WHERE fdst.id = fds.id), -1 ))
AND aarh.code_status = #{criteria.docCodeStatus, jdbcType = VARCHAR}
-- AND (aarh.code_status = 'leader' or aarh.code_status = 'documentor') AND (aarh.code_status = 'leader' or aarh.code_status = 'documentor' or aarh.code_status = 'leaderRepulse')
AND ( (isnull(aarh.commit_flag, 0) = 0 and (aarh.code_status = 'documentor' or aarh.code_status = 'leader' or aarh.code_status = 'person')) or (isnull(aarh.commit_flag, 0) = 0 and (aarh.code_status = 'leaderRepulse' or aarh.code_status = 'acAdminRepulse' or aarh.code_status = 'leaderRepulseToPerson')) )
AND isnull(aarh.commit_flag, 0) = #{criteria.docCommitFlag, jdbcType = BIT}
AND (aarh.code_status = 'documentor' or aarh.code_status = 'leaderRepulse' or aarh.code_status = 'acAdminRepulse' or aarh.code_status = 'leaderRepulseToPerson')

union
and exists (SELECT 1 FROM pm_employee_job pej_t WHERE pej_t.employee_id = pe.id AND pej_t.enabled_flag = 1 and pej_t.job_main_flag = 1 AND pej_t.dept_id IN
#{item, jdbcType=BIGINT}
)
AND EXISTS ( SELECT 1 FROM pm_employee_job pejst WHERE pejst.id = pejs.id AND pejst.job_id != isnull(( SELECT fdst.admin_job_id FROM fnd_dept fdst WHERE fdst.id = fds.id ), -1 ))

